import sys
from collections import defaultdict

def count_similar_pairs(n, d, a):
    count = 0
    a_dict = defaultdict(list)
    for i, num in enumerate(a):
        a_dict[num].append(i)

    for num in a_dict:
        count += (len(a_dict[num]) * (len(a_dict[num]) - 1)) // 2

    for num in a_dict:
        for offset in range(1, d + 1):
            if num + offset in a_dict:
                count += len(a_dict[num]) * len(a_dict[num + offset])
            if num - offset in a_dict:
                count += len(a_dict[num]) * len(a_dict[num - offset])

    return count // 2

def main():
    n, d = map(int, input().split())
    a = list(map(int, input().split()))
    print(count_similar_pairs(n, d, a))

if __name__ == "__main__":
    main()
